Minimal fix (keep current behavior except add small clock-skew grace, still rejects truly expired tokens):

```js
const CLOCK_SKEW_MS = 30_000;

export async function authMiddleware(req, res, next) {
  const token = getBearerToken(req);
  if (!token) return res.status(401).json({ error: 'missing_token' });

  const payload = verifyJwt(token);
  const nowMs = Date.now();
  const expMs = payload.exp * 1000;

  if (nowMs - expMs > CLOCK_SKEW_MS) {
    return res.status(401).json({ error: 'expired_token' });
  }

  req.userId = payload.sub;
  return next();
}
```

Regression test (Jest; ensures boundary within grace is accepted):

```js
import { authMiddleware } from './authMiddleware';

jest.mock('./getBearerToken', () => ({ getBearerToken: jest.fn() }));
jest.mock('./verifyJwt', () => ({ verifyJwt: jest.fn() }));

import { getBearerToken } from './getBearerToken';
import { verifyJwt } from './verifyJwt';

test('accepts token expired at boundary within 30s clock skew grace', async () => {
  jest.useFakeTimers().setSystemTime(new Date('2020-01-01T00:00:30.000Z'));
  getBearerToken.mockReturnValue('t');
  verifyJwt.mockReturnValue({ sub: 'u1', exp: 1577836800 }); // 2020-01-01T00:00:00Z

  const req = {};
  const res = { status: jest.fn().mockReturnThis(), json: jest.fn() };
  const next = jest.fn();

  await authMiddleware(req, res, next);

  expect(res.status).not.toHaveBeenCalled();
  expect(next).toHaveBeenCalled();
  expect(req.userId).toBe('u1');
});
```

