const { promisify } = require('util');

const findUserAsync = promisify(db.findUser.bind(db));
const auditLogAsync = promisify(audit.log.bind(audit));
const cacheSetAsync = promisify(cache.set.bind(cache));

async function loadUser(id, next) {
  try {
    if (!id) throw new Error('missing_id');

    const user = await findUserAsync(id);
    if (!user) throw new Error('not_found');

    await auditLogAsync(user.id);
    await cacheSetAsync(user.id, user);

    next(null, user);
  } catch (err) {
    next(err); // single mapping point
  }
}
